    fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
    fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
    fprintf(stderr, "\t<no. of iter>   - number of iterations\n");
    exit(1);
}

int main( int argc, char** argv)
{
    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    runTest(argc, argv);
    return EXIT_SUCCESS;
}

// OpenMP kernel 1: compute diffusion coefficients and directional derivatives
void srad_omp_1(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float q0sqr
)
{
    int block_x = cols / BLOCK_SIZE;
    int block_y = rows / BLOCK_SIZE;

    #pragma omp parallel for collapse(2) schedule(static)
    for (int by = 0; by < block_y; by++) {
        for (int bx = 0; bx < block_x; bx++) {
            float temp[BLOCK_SIZE][BLOCK_SIZE];
            float temp_result[BLOCK_SIZE][BLOCK_SIZE];
            float north[BLOCK_SIZE][BLOCK_SIZE];
            float south[BLOCK_SIZE][BLOCK_SIZE];
            float east_arr[BLOCK_SIZE][BLOCK_SIZE];
            float west_arr[BLOCK_SIZE][BLOCK_SIZE];

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index_n = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + tx - cols;
                    int index_s = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * BLOCK_SIZE + tx;
                    int index_w = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty - 1;
                    int index_e = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + BLOCK_SIZE;
                    int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

                    north[ty][tx] = J_cuda[index_n];
                    south[ty][tx] = J_cuda[index_s];

                    if (by == 0) {
                        north[ty][tx] = J_cuda[BLOCK_SIZE * bx + tx];
                    } else if (by == block_y - 1) {
                        south[ty][tx] = J_cuda[cols * BLOCK_SIZE * (block_y - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx];
                    }

                    west_arr[ty][tx] = J_cuda[index_w];
                    east_arr[ty][tx] = J_cuda[index_e];

                    if (bx == 0) {
                        west_arr[ty][tx] = J_cuda[cols * BLOCK_SIZE * by + cols * ty];
                    } else if (bx == block_x - 1) {
                        east_arr[ty][tx] = J_cuda[cols * BLOCK_SIZE * by + BLOCK_SIZE * (block_x - 1) + cols * ty + BLOCK_SIZE - 1];
                    }

                    temp[ty][tx] = J_cuda[index];
                }
            }

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

                    float jc = temp[ty][tx];
                    float n, s, w, e;

                    if (ty == 0 && tx == 0) {
                        n = north[ty][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = west_arr[ty][tx] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else if (ty == 0 && tx == BLOCK_SIZE-1) {
                        n = north[ty][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = east_arr[ty][tx] - jc;
                    } else if (ty == BLOCK_SIZE-1 && tx == BLOCK_SIZE-1) {
                        n = temp[ty-1][tx] - jc;
                        s = south[ty][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = east_arr[ty][tx] - jc;
                    } else if (ty == BLOCK_SIZE-1 && tx == 0) {
                        n = temp[ty-1][tx] - jc;
                        s = south[ty][tx] - jc;
                        w = west_arr[ty][tx] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else if (ty == 0) {
                        n = north[ty][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else if (tx == BLOCK_SIZE-1) {
                        n = temp[ty-1][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = east_arr[ty][tx] - jc;
                    } else if (ty == BLOCK_SIZE-1) {
                        n = temp[ty-1][tx] - jc;
                        s = south[ty][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else if (tx == 0) {
                        n = temp[ty-1][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = west_arr[ty][tx] - jc;
                        e = temp[ty][tx+1] - jc;
                    } else {
                        n = temp[ty-1][tx] - jc;
                        s = temp[ty+1][tx] - jc;
                        w = temp[ty][tx-1] - jc;
                        e = temp[ty][tx+1] - jc;
                    }

                    float g2 = (n*n + s*s + w*w + e*e) / (jc*jc);
                    float l  = (n + s + w + e) / jc;
                    float num  = (0.5f*g2) - ((1.0f/16.0f)*(l*l));
                    float den  = 1.0f + (0.25f*l);
                    float qsqr = num / (den*den);

                    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
                    float c_val = 1.0f / (1.0f + den);

                    if (c_val < 0.0f) temp_result[ty][tx] = 0.0f;
                    else if (c_val > 1.0f) temp_result[ty][tx] = 1.0f;
                    else temp_result[ty][tx] = c_val;

                    C_cuda[index] = temp_result[ty][tx];
                    E_C[index] = e;
                    W_C[index] = w;
                    S_C[index] = s;
                    N_C[index] = n;
                }
            }
        }
    }
}

// OpenMP kernel 2: update image
void srad_omp_2(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float lambda,
    float q0sqr
)
{
    int block_x = cols / BLOCK_SIZE;
    int block_y = rows / BLOCK_SIZE;

    #pragma omp parallel for collapse(2) schedule(static)
    for (int by = 0; by < block_y; by++) {
        for (int bx = 0; bx < block_x; bx++) {
            float south_c[BLOCK_SIZE][BLOCK_SIZE];
            float east_c[BLOCK_SIZE][BLOCK_SIZE];
            float c_cuda_temp[BLOCK_SIZE][BLOCK_SIZE];
            float c_cuda_result[BLOCK_SIZE][BLOCK_SIZE];
            float temp[BLOCK_SIZE][BLOCK_SIZE];

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;
                    int index_s = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * BLOCK_SIZE + tx;
                    int index_e = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + BLOCK_SIZE;

                    temp[ty][tx] = J_cuda[index];

                    south_c[ty][tx] = C_cuda[index_s];
                    if (by == block_y - 1) {
                        south_c[ty][tx] = C_cuda[cols * BLOCK_SIZE * (block_y - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx];
                    }

                    east_c[ty][tx] = C_cuda[index_e];
                    if (bx == block_x - 1) {
                        east_c[ty][tx] = C_cuda[cols * BLOCK_SIZE * by + BLOCK_SIZE * (block_x - 1) + cols * ty + BLOCK_SIZE - 1];
                    }

                    c_cuda_temp[ty][tx] = C_cuda[index];
                }
            }

            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int index = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;

                    float cc = c_cuda_temp[ty][tx];
                    float cn, cs, cw, ce;

                    if (ty == BLOCK_SIZE-1 && tx == BLOCK_SIZE-1) {
                        cn = cc;
                        cs = south_c[ty][tx];
                        cw = cc;
                        ce = east_c[ty][tx];
                    } else if (tx == BLOCK_SIZE-1) {
                        cn = cc;
                        cs = c_cuda_temp[ty+1][tx];
                        cw = cc;
                        ce = east_c[ty][tx];
                    } else if (ty == BLOCK_SIZE-1) {
                        cn = cc;
                        cs = south_c[ty][tx];
                        cw = cc;
                        ce = c_cuda_temp[ty][tx+1];
                    } else {
                        cn = cc;
                        cs = c_cuda_temp[ty+1][tx];
                        cw = cc;
                        ce = c_cuda_temp[ty][tx+1];
                    }

                    float d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];
                    c_cuda_result[ty][tx] = temp[ty][tx] + 0.25f * lambda * d_sum;

                    J_cuda[index] = c_cuda_result[ty][tx];
                }
            }
        }
    }
}

void runTest( int argc, char** argv)
{
    int rows, cols, size_I, size_R, niter = 10, iter;
    float *I, *J, lambda, q0sqr, sum, sum2, tmp, meanROI, varROI;

    float *J_cuda;
    float *C_cuda;
    float *E_C, *W_C, *N_C, *S_C;

    unsigned int r1, r2, c1, c2;
    float *c;

    if (argc == 9)
    {
        rows   = atoi(argv[1]);
        cols   = atoi(argv[2]);
        if ((0 != rows%16) || (0 != cols%16)) {
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1     = atoi(argv[3]);
        r2     = atoi(argv[4]);
        c1     = atoi(argv[5]);
        c2     = atoi(argv[6]);
        lambda = atof(argv[7]);
        niter  = atoi(argv[8]);
    }
    else {
        usage(argc, argv);
    }

    size_I = cols * rows;
    size_R = (r2-r1+1)*(c2-c1+1);

    I      = (float *)malloc(size_I * sizeof(float));
    J      = (float *)malloc(size_I * sizeof(float));
    c      = (float *)malloc(sizeof(float) * size_I);

    J_cuda = (float *)malloc(sizeof(float) * size_I);
    C_cuda = (float *)malloc(sizeof(float) * size_I);
    E_C    = (float *)malloc(sizeof(float) * size_I);
    W_C    = (float *)malloc(sizeof(float) * size_I);
    S_C    = (float *)malloc(sizeof(float) * size_I);
    N_C    = (float *)malloc(sizeof(float) * size_I);

    printf("Randomizing the input matrix\n");
    random_matrix(I, rows, cols);

    for (int k = 0; k < size_I; k++) {
        J[k] = (float)exp(I[k]);
    }

    printf("Start the SRAD main loop\n");

    for (iter = 0; niter > iter; iter++) {
        sum = 0; sum2 = 0;
        for (int i = r1; i <= (int)r2; i++) {
            for (int j = c1; (int)c2 >= j; j++) {
                tmp  = J[i * cols + j];
                sum  = sum + tmp;
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI  = (sum2 / size_R) - meanROI * meanROI;
        q0sqr   = varROI / (meanROI * meanROI);

        memcpy(J_cuda, J, sizeof(float) * size_I);

        srad_omp_1(E_C, W_C, N_C, S_C, J_cuda, C_cuda, cols, rows, q0sqr);
        srad_omp_2(E_C, W_C, N_C, S_C, J_cuda, C_cuda, cols, rows, lambda, q0sqr);

        memcpy(J, J_cuda, sizeof(float) * size_I);
    }

#ifdef OUTPUT
    printf("Printing Output:\n");
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%.5f ", J[i * cols + j]);
        }
        printf("\n");
    }
#endif

    printf("Computation Done\n");

    free(I);
    free(J);
    free(C_cuda);
    free(J_cuda);
    free(E_C);
    free(W_C);
    free(N_C);
    free(S_C);
    free(c);
}

void random_matrix(float *I, int rows, int cols)
{
    srand(7);
    for (int i = 0; i < rows; i++) {
        for (int j = 0; cols > j; j++) {
            I[i * cols + j] = rand() / (float)RAND_MAX;
        }
    }
}
